import java.util.*;
import java.lang.*;
import java.io.*;

class Codechef
{
    public static void main (String[] args) throws java.lang.Exception
    {
        // Initialize the upper limit for finding primes
        int n = 505;

        // Create an array to mark primes (true means prime)
        boolean[] prime_list = new boolean[n + 1];
        Arrays.fill(prime_list, true); // Mark all numbers as prime initially
        int pr = 2;

        // Sieve of Eratosthenes algorithm to mark non-prime numbers
        while (pr * pr <= n) {
            if (prime_list[pr]) {
                // Mark all multiples of pr as non-prime (starting from pr * 2)
                for (int i = pr * 2; i <= n; i += pr) {
                    prime_list[i] = false;
                }
            }
            pr++;
        }

        // Mark 0 and 1 as non-prime (special cases)
        prime_list[0] = false;
        prime_list[1] = false;

        // Taking input for d and p
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
        String[] input = reader.readLine().split(" ");
        int d = Integer.parseInt(input[0]);
        int p = Integer.parseInt(input[1]);

        // Calculate the new value of n as d divided by p
        n = d / p;
        int count = 0;

        // Loop through numbers starting from 2 (since 0 and 1 are not prime)
        for (int i = 2; i < n; i++) {
            boolean prime_time = true;

            // Check p numbers in the sequence: i, i + n, i + 2n, ..., i + (p-1)n
            for (int j = 0; j < p; j++) {
                int num = i + j * n;

                // If any number in this sequence is not prime, mark prime_time as false
                if (!prime_list[num]) {
                    prime_time = false;
                    break;
                }
            }

            // If all numbers in the sequence are prime, increment the count
            if (prime_time) {
                count++;
            }
        }

        // Output the final count of valid prime sequences
        System.out.println(count);
    }
}
